 // (nil pointer dereference in DoltDB.SetCrashOnFatalError) or a "database is
 // locked" error.
 //
+// LOCK files can appear at multiple nesting levels, including stats databases:
+//   - <db>/.dolt/noms/LOCK
+//   - <db>/.dolt/stats/.dolt/noms/LOCK
+//   - .dolt/noms/LOCK (root-level)
+//
+// This function uses filepath.WalkDir to recursively find and remove all files
+// named "LOCK" inside "noms" directories under doltDir.
+//
 // This function is safe to call before starting or connecting to a Dolt server
-// because the server is not yet using the databases. It scans all subdirectories
-// of doltDir for <db>/.dolt/noms/LOCK and removes them.
+// because the server is not yet using the databases.
 //
 // Returns the number of lock files removed. Errors removing individual files
 // are collected but do not abort the scan.
 func CleanStaleNomsLocks(doltDir string) (removed int, errs []error) {
-	entries, err := os.ReadDir(doltDir)
-	if err != nil {
-		// Directory doesn't exist or can't be read — nothing to clean.
+	// Quick check: if directory doesn't exist, nothing to clean.
+	if _, err := os.Stat(doltDir); err != nil {
 		return 0, nil
 	}

-	for _, entry := range entries {
-		if !entry.IsDir() {
-			continue
+	walkErr := filepath.WalkDir(doltDir, func(path string, d fs.DirEntry, err error) error {
+		if err != nil {
+			return nil // skip unreadable entries
 		}
-		lockPath := filepath.Join(doltDir, entry.Name(), ".dolt", "noms", "LOCK")
-		if _, statErr := os.Stat(lockPath); os.IsNotExist(statErr) {
-			continue
+		if d.IsDir() {
+			return nil
 		}
-		if rmErr := os.Remove(lockPath); rmErr != nil {
-			errs = append(errs, fmt.Errorf("removing %s: %w", lockPath, rmErr))
-		} else {
-			removed++
+		// Match files named "LOCK" inside a "noms" directory.
+		if d.Name() == "LOCK" && filepath.Base(filepath.Dir(path)) == "noms" {
+			if rmErr := os.Remove(path); rmErr != nil {
+				errs = append(errs, fmt.Errorf("removing %s: %w", path, rmErr))
+			} else {
+				removed++
+			}
 		}
+		return nil
+	})
+	if walkErr != nil {
+		errs = append(errs, fmt.Errorf("walking %s: %w", doltDir, walkErr))
 	}

 	return removed, errs

@@ -130,4 +130,93 @@ func TestCleanStaleNomsLocks(t *testing.T) {
 			t.Fatalf("expected 0 removed, got %d", removed)
 		}
 	})
+
+	t.Run("removes nested stats LOCK files", func(t *testing.T) {
+		t.Parallel()
+		dir := t.TempDir()
+
+		// Simulate the exact paths from the bug report:
+		// .beads/dolt/lista/.dolt/stats/.dolt/noms/LOCK
+		// .beads/dolt/.dolt/noms/LOCK
+		// .beads/dolt/.dolt/stats/.dolt/noms/LOCK
+		paths := []string{
+			filepath.Join(dir, "lista", ".dolt", "stats", ".dolt", "noms"),
+			filepath.Join(dir, ".dolt", "noms"),
+			filepath.Join(dir, ".dolt", "stats", ".dolt", "noms"),
+		}
+		for _, p := range paths {
+			if err := os.MkdirAll(p, 0755); err != nil {
+				t.Fatal(err)
+			}
+			if err := os.WriteFile(filepath.Join(p, "LOCK"), []byte("stale"), 0600); err != nil {
+				t.Fatal(err)
+			}
+		}
+
+		// Also add a normal db-level lock
+		normalNoms := filepath.Join(dir, "lista", ".dolt", "noms")
+		if err := os.MkdirAll(normalNoms, 0755); err != nil {
+			t.Fatal(err)
+		}
+		if err := os.WriteFile(filepath.Join(normalNoms, "LOCK"), []byte("stale"), 0600); err != nil {
+			t.Fatal(err)
+		}
+
+		removed, errs := CleanStaleNomsLocks(dir)
+		if len(errs) > 0 {
+			t.Fatalf("unexpected errors: %v", errs)
+		}
+		if removed != 4 {
+			t.Fatalf("expected 4 removed, got %d", removed)
+		}
+
+		// Verify all are gone
+		for _, p := range paths {
+			lockPath := filepath.Join(p, "LOCK")
+			if _, err := os.Stat(lockPath); !os.IsNotExist(err) {
+				t.Fatalf("LOCK file should have been removed: %s", lockPath)
+			}
+		}
+		normalLock := filepath.Join(normalNoms, "LOCK")
+		if _, err := os.Stat(normalLock); !os.IsNotExist(err) {
+			t.Fatalf("LOCK file should have been removed: %s", normalLock)
+		}
+	})
+
+	t.Run("ignores LOCK files not in noms directory", func(t *testing.T) {
+		t.Parallel()
+		dir := t.TempDir()
+
+		// A LOCK file in a non-noms directory should be ignored
+		otherDir := filepath.Join(dir, "mydb", ".dolt", "other")
+		if err := os.MkdirAll(otherDir, 0755); err != nil {
+			t.Fatal(err)
+		}
+		if err := os.WriteFile(filepath.Join(otherDir, "LOCK"), []byte("keep"), 0600); err != nil {
+			t.Fatal(err)
+		}
+
+		// A real noms LOCK should still be removed
+		nomsDir := filepath.Join(dir, "mydb", ".dolt", "noms")
+		if err := os.MkdirAll(nomsDir, 0755); err != nil {
+			t.Fatal(err)
+		}
+		if err := os.WriteFile(filepath.Join(nomsDir, "LOCK"), []byte("stale"), 0600); err != nil {
+			t.Fatal(err)
+		}
+
+		removed, errs := CleanStaleNomsLocks(dir)
+		if len(errs) > 0 {
+			t.Fatalf("unexpected errors: %v", errs)
+		}
+		if removed != 1 {
+			t.Fatalf("expected 1 removed, got %d", removed)
+		}
+
+		// The non-noms LOCK should still exist
+		otherLock := filepath.Join(otherDir, "LOCK")
+		if _, err := os.Stat(otherLock); err != nil {
+			t.Fatalf("non-noms LOCK file should not have been removed: %s", otherLock)
+		}
+	})
